CREATE MATERIALIZED VIEW public.attempt_message_tree_mv AS
 WITH RECURSIVE walk AS (
         SELECT sm.id AS message_id,
            ARRAY[sm.id] AS branch_path,
            0 AS depth
           FROM (public.attempt_message_entry sm
             LEFT JOIN public.attempt_message_tree_entry smt ON (((smt.child_id = sm.id) AND (smt.active = true))))
          WHERE (smt.child_id IS NULL)
        UNION ALL
         SELECT smt.child_id AS message_id,
            (w.branch_path || smt.child_id),
            (w.depth + 1)
           FROM (public.attempt_message_tree_entry smt
             JOIN walk w ON ((w.message_id = smt.parent_id)))
          WHERE (smt.active = true)
        )
 SELECT message_id,
    branch_path,
    depth
   FROM walk
  WITH NO DATA;


